mapper.select:
SELECT IMG_PATH
FROM NMCP_PROD_IMG_DTL
WHERE PROD_ID = #{prodId}
AND SNTY_COLOR_CD = #{sntyColorCd}
AND  ROWNUM=1
ORDER BY IMG_TYPE_CD ASC

SELECT SELF_DLVRY_IDX , USIM_PROD_ID , USIM_PROD_DTL_ID , CSTMR_NAME , CSTMR_NATIVE_RRN , ONLINE_AUTH_TYPE , ONLINE_AUTH_INFO , ONLINE_AUTH_DI , DLVRY_NAME , DLVRY_TEL_FN , DLVRY_TEL_MN , DLVRY_TEL_RN , DLVRY_POST , DLVRY_ADDR , DLVRY_ADDR_DTL , DLVRY_MEMO , SELF_MEMO , REQ_USIM_SN , DLVRY_STATE_CODE , SELF_STATE_CODE , DLVRY_NO , TB_CD , CONTRACT_NUM , CRET_ID , RVISN_ID , RVISN_DTTM , SYS_RDATE , REQ_BUY_QNTY , USIM_UCOST , USIM_PRICE , (SELECT CD_DTL.DTL_CD_DESC FROM NMCP_CD_DTL CD_DTL WHERE CD_DTL.CD_GROUP_ID = 'PERCEL' AND CD_DTL.USE_YN = 'Y' AND CD_DTL.DTL_CD = TB_CD) AS PERCEL_URL , '01' AS DLVRY_KIND FROM MCP_REQUEST_SELF_DLVRY WHERE 1=1
AND SELF_DLVRY_IDX = #{selfDlvryIdx}
AND ONLINE_AUTH_DI = #{onlineAuthDi}
AND CRET_ID = #{cretId}
AND CSTMR_NAME = #{cstmrName} AND DLVRY_TEL_FN || DLVRY_TEL_MN || DLVRY_TEL_RN = #{dlvryTelFn}||#{dlvryTelMn}||#{dlvryTelRn}
AND SYS_RDATE BETWEEN TO_DATE(#{sysRdateS}||'000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{sysRdateE}||'235959', 'YYYYMMDDHH24MISS')
UNION ALL SELECT SELF_DLVRY_IDX , USIM_PROD_ID , USIM_PROD_DTL_ID , CSTMR_NAME , CSTMR_NATIVE_RRN , ONLINE_AUTH_TYPE , ONLINE_AUTH_INFO , ONLINE_AUTH_DI , DLVRY_NAME , DLVRY_TEL_FN , DLVRY_TEL_MN , DLVRY_TEL_RN , DLVRY_POST , DLVRY_ADDR , DLVRY_ADDR_DTL , DLVRY_MEMO , SELF_MEMO , REQ_USIM_SN , DLVRY_STATE_CODE , SELF_STATE_CODE , DLVRY_NO , TB_CD , CONTRACT_NUM , CRET_ID , RVISN_ID , RVISN_DTTM , SYS_RDATE , REQ_BUY_QNTY , USIM_UCOST , USIM_AMT AS USIM_PRICE , (SELECT CD_DTL.DTL_CD_DESC FROM NMCP_CD_DTL CD_DTL WHERE CD_DTL.CD_GROUP_ID = 'PERCEL' AND CD_DTL.USE_YN = 'Y' AND CD_DTL.DTL_CD = TB_CD) AS PERCEL_URL , '02' AS DLVRY_KIND FROM MCP_REQUEST_NOW_DLVRY WHERE 1=1
AND SELF_DLVRY_IDX = #{selfDlvryIdx}
AND ONLINE_AUTH_DI = #{onlineAuthDi}
AND CRET_ID = #{cretId}
AND CSTMR_NAME = #{cstmrName} AND DLVRY_TEL_FN || DLVRY_TEL_MN || DLVRY_TEL_RN = #{dlvryTelFn}||#{dlvryTelMn}||#{dlvryTelRn}
AND SYS_RDATE BETWEEN TO_DATE(#{sysRdateS}||'000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{sysRdateE}||'235959', 'YYYYMMDDHH24MISS')
ORDER BY SELF_DLVRY_IDX DESC

SELECT COUNT(*) FROM
(
SELECT
  SELF_DLVRY_IDX
FROM MCP_REQUEST_SELF_DLVRY
WHERE 1=1

        AND SELF_DLVRY_IDX = #{selfDlvryIdx}


        AND ONLINE_AUTH_DI = #{onlineAuthDi}


        AND CRET_ID = #{cretId}


        AND CSTMR_NAME = #{cstmrName} AND DLVRY_TEL_FN || DLVRY_TEL_MN || DLVRY_TEL_RN = #{dlvryTelFn}||#{dlvryTelMn}||#{dlvryTelRn}


        AND SYS_RDATE BETWEEN  TO_DATE(#{sysRdateS}||'000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{sysRdateE}||'235959', 'YYYYMMDDHH24MISS')

 UNION ALL
 SELECT
      SELF_DLVRY_IDX
 FROM MCP_REQUEST_NOW_DLVRY
 WHERE 1=1

        AND SELF_DLVRY_IDX = #{selfDlvryIdx}


        AND ONLINE_AUTH_DI = #{onlineAuthDi}


        AND CRET_ID = #{cretId}


        AND CSTMR_NAME = #{cstmrName} AND DLVRY_TEL_FN || DLVRY_TEL_MN || DLVRY_TEL_RN = #{dlvryTelFn}||#{dlvryTelMn}||#{dlvryTelRn}


        AND SYS_RDATE BETWEEN  TO_DATE(#{sysRdateS}||'000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{sysRdateE}||'235959', 'YYYYMMDDHH24MISS')

 ) UNION_GROUP

SELECT
DLVRY_STATE_CODE AS STATE , COUNT(DLVRY_STATE_CODE) AS STATE_COUNT
  FROM MCP_REQUEST_SELF_DLVRY
  WHERE SELF_STATE_CODE = '01'

      AND SELF_DLVRY_IDX = #{selfDlvryIdx}


      AND ONLINE_AUTH_DI = #{onlineAuthDi}


      AND CRET_ID = #{cretId}


      AND CSTMR_NAME = #{cstmrName} AND DLVRY_TEL_FN || DLVRY_TEL_MN || DLVRY_TEL_RN = #{dlvryTelFn}||#{dlvryTelMn}||#{dlvryTelRn}


      AND SYS_RDATE BETWEEN  TO_DATE(#{sysRdateS}||'000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{sysRdateE}||'235959', 'YYYYMMDDHH24MISS')

 GROUP BY DLVRY_STATE_CODE

SELECT
DLVRY_STATE_CODE AS STATE , COUNT(DLVRY_STATE_CODE) AS STATE_COUNT
  FROM MCP_REQUEST_NOW_DLVRY
  WHERE 1=1

      AND SELF_DLVRY_IDX = #{selfDlvryIdx}


      AND ONLINE_AUTH_DI = #{onlineAuthDi}


      AND CRET_ID = #{cretId}


      AND CSTMR_NAME = #{cstmrName} AND DLVRY_TEL_FN || DLVRY_TEL_MN || DLVRY_TEL_RN = #{dlvryTelFn}||#{dlvryTelMn}||#{dlvryTelRn}


      AND SYS_RDATE BETWEEN  TO_DATE(#{sysRdateS}||'000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{sysRdateE}||'235959', 'YYYYMMDDHH24MISS')

 GROUP BY DLVRY_STATE_CODE

SELECT UNION_GROUP.REQUEST_STATE_CODE AS STATE, COUNT(UNION_GROUP.REQUEST_STATE_CODE) AS STATE_COUNT FROM ( SELECT A.REQUEST_KEY ,A.REQUEST_STATE_CODE FROM MCP_REQUEST A ,MCP_REQUEST_CSTMR B ,MCP_REQUEST_STATE C ,MCP_REQUEST_SALEINFO D ,MCP_REQUEST_DLVRY E WHERE 1=1
AND( (B.CSTMR_NAME = #{cstmrName} AND B.CSTMR_MOBILE_FN || B.CSTMR_MOBILE_MN || B.CSTMR_MOBILE_RN = #{cstmrMobileFn}||#{cstmrMobileMn}||#{cstmrMobileRn} ) OR ( E.DLVRY_NAME = #{cstmrName} AND E.DLVRY_MOBILE_FN || E.DLVRY_MOBILE_MN || E.DLVRY_MOBILE_RN = #{cstmrMobileFn}||#{cstmrMobileMn}||#{cstmrMobileRn} ))
AND A.CRET_ID = #{cretId}
AND A.REQ_BUY_TYPE = #{reqBuyType}
AND A.REQUEST_KEY = B.REQUEST_KEY AND B.REQUEST_KEY = C.REQUEST_KEY AND A.REQUEST_KEY = D.REQUEST_KEY AND A.REQUEST_KEY = E.REQUEST_KEY AND A.REQ_IN_DAY BETWEEN TO_DATE(#{searchStart}||'000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{searchEnd}||'235959', 'YYYYMMDDHH24MISS') UNION ALL SELECT A.REQUEST_KEY ,A.REQUEST_STATE_CODE FROM NMCP_REQUEST_APD A ,NMCP_REQUEST_APD_STATE C ,NMCP_REQUEST_APD_SALEINFO D ,MCP_REQUEST_DLVRY E WHERE 1=1
AND E.DLVRY_NAME = #{cstmrName} AND E.DLVRY_MOBILE_FN || E.DLVRY_MOBILE_MN || E.DLVRY_MOBILE_RN = #{cstmrMobileFn}||#{cstmrMobileMn}||#{cstmrMobileRn}
AND A.CRET_ID = #{cretId}
AND A.REQUEST_KEY = C.REQUEST_KEY AND A.REQUEST_KEY = D.REQUEST_KEY AND A.REQUEST_KEY = E.REQUEST_KEY AND A.REQ_IN_DAY BETWEEN TO_DATE(#{searchStart}||'000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{searchEnd}||'235959', 'YYYYMMDDHH24MISS') ) UNION_GROUP GROUP BY UNION_GROUP.REQUEST_STATE_CODE
